const staticData = $getWorkflowStaticData('global');
if (!staticData.history) staticData.history = {};
const phone = $input.item.json.phone;
return [{
  json: {
    ...$input.item.json,
    history: staticData.history[phone] || ''
  }
}];

const staticData = $getWorkflowStaticData('global');
if (!staticData.history) staticData.history = {};
const extract = $('Extract Fields').item.json;
const phone = extract.phone;
const msg = extract.msg;
const content = $input.item.json.choices[0].message.content;
const old = staticData.history[phone] || '';
staticData.history[phone] = `${old} Student: ${msg} Assistant:${content} `;
staticData.lastUpdated = new Date().toISOString();
return [{
  json: {
    phone,
    from: extract.from,
    msg,
    content
  }
}];

const content = $input.item.json.content;
const match = content.match(/\{[\s\S]*\}/);
if (!match) {
  throw new Error('No JSON object found in GPT reply: ' + content);
}
const booking = JSON.parse(match[0]);
return [{
  json: {
    ...$input.item.json,
    name: booking.name || '',
    postcode: booking.postcode || '',
    gearbox: booking.gearbox || '',
    testDate: booking.testDate || '',
    experience: booking.experience || '',
    lessonDateTime: booking.lessonDateTime || ''
  }
}];

const booking = $input.item.json;
const raw = booking.lessonDateTime;
let isFuture = false;
let parsedTime = null;
let reason = '';

if (!raw) {
  reason = 'no lessonDateTime provided';
} else {
  const t = Date.parse(raw);
  if (isNaN(t)) {
    reason = 'unparseable date: ' + raw;
  } else {
    parsedTime = new Date(t).toISOString();
    const now = Date.now();
    isFuture = t > now;
    if (!isFuture) reason = 'date is in the past';
  }
}

return [{
  json: {
    ...booking,
    isFuture,
    parsedTime,
    validationReason: reason
  }
}];

const events = $input.all();
const slotFree = events.length === 0;
const booking = $('Parse Booking JSON').item.json;
return [{
  json: {
    slotFree,
    conflictingEvents: events.length,
    name: booking.name,
    postcode: booking.postcode,
    gearbox: booking.gearbox,
    testDate: booking.testDate,
    experience: booking.experience,
    phone: booking.phone,
    lessonDateTime: booking.lessonDateTime
  }
}];

